# day1_checkin.py — structured check-in for war room; posts summary to Slack
import requests, os
from prometheus_api_client import PrometheusConnect

prom = PrometheusConnect(url="http://prometheus:9090")

def get_metric(query: str) -> float:
    result = prom.custom_query(query)
    return float(result[0]["value"][1]) if result else float("nan")

def run_checkin(version: str = "v2") -> dict:
    return {
        "error_rate_pct": get_metric(
            f'rate(claude_http_errors_total{{version="{version}",status=~"5.."}}[5m]) '
            f'/ rate(claude_http_requests_total{{version="{version}"}}[5m]) * 100'
        ),
        "p99_latency_ms": get_metric(
            f'histogram_quantile(0.99, rate(claude_latency_seconds_bucket{{version="{version}"}}[5m])) * 1000'
        ),
        "requests_per_sec": get_metric(
            f'rate(claude_http_requests_total{{version="{version}"}}[5m])'
        ),
        "eval_score_pct": get_metric("claude_eval_score_latest * 100"),
    }

def post_to_slack(checkin: dict, elapsed_min: int):
    status = "OK" if checkin["error_rate_pct"] < 0.05 else "ALERT"
    text = (
        f"*Day-1 Check-in T+{elapsed_min}m* [{status}]\n"
        f"Error rate: {checkin['error_rate_pct']:.3f}% | "
        f"P99 latency: {checkin['p99_latency_ms']:.0f}ms | "
        f"RPS: {checkin['requests_per_sec']:.0f} | "
        f"Eval score: {checkin['eval_score_pct']:.1f}%"
    )
    requests.post(os.environ["SLACK_WEBHOOK_URL"], json={"text": text})

checkin = run_checkin()
post_to_slack(checkin, elapsed_min=int(os.environ.get("ELAPSED_MIN", 5)))

# t_plus_1h_report.py — generate and post T+1h status report
def generate_status_report(metrics: dict, version: str, feature_name: str) -> str:
    status = "On track" if metrics["error_rate_pct"] < 0.05 else "Under observation"
    return f"""
*{feature_name} Launch — T+1h Status*

Status: {status}
Traffic on v{version}: {metrics['traffic_pct']:.0f}%

Key Metrics (last 60m):
• Error rate: {metrics['error_rate_pct']:.3f}% (threshold: 0.05%)
• P99 latency: {metrics['p99_latency_ms']:.0f}ms (baseline: {metrics['baseline_p99_ms']:.0f}ms)
• Requests served: {metrics['total_requests']:,}
• Eval score: {metrics['eval_score_pct']:.1f}% (threshold: 98%)

Issues: {metrics.get('open_issues', 'None')}
Next check-in: T+4h
On-call: {metrics.get('oncall_name', 'See PagerDuty')}

Full dashboard: {metrics.get('dashboard_url', 'https://grafana/d/launch')}
"""

# Post to internal channels
channels = ["#launches", "#engineering-all", "#customer-success"]
report = generate_status_report(collect_metrics(), version="2", feature_name="Claude Feature V2")
for channel in channels:
    post_to_slack(channel, report)
